function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function asArr(v) {
  if (Array.isArray(v)) return v.filter(Boolean).map(safeStr);
  if (typeof v === 'string' && v.trim()) { try { const p = JSON.parse(v); if (Array.isArray(p)) return p.filter(Boolean).map(safeStr); } catch (e) {} }
  return [];
}
function parseObj(v) {
  if (!v) return {};
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  try { const p = JSON.parse(String(v)); return (p && typeof p === 'object' && !Array.isArray(p)) ? p : {}; }
  catch (e) { return {}; }
}
function num(v, fb) { const n = Number(String(v ?? '').replace(',', '.')); return Number.isFinite(n) ? n : fb; }

const row = $json;
const sl = parseObj(row.sourceLock);
const va = parseObj(row.visualAnchors);

return {
  json: {
    vorgangKey: safeStr(row.vorgangKey),
    vorgangsnummer: safeStr(row.vorgangsnummer),
    title: safeStr(row.title),

    relevanz: num(row.relevanz, 0),
    sprengstoff: safeStr(row.sprengstoff) || 'KEINER',
    empfehlung: safeStr(row.empfehlung) || 'BEOBACHTEN',
    kommunikationspotenzial: num(row.kommunikationspotenzial, 0),
    oeffentlicheGelderBetroffen: row.oeffentlicheGelderBetroffen === true,

    sourceTopic: safeStr(sl.sourceTopic),
    sourceConflict: safeStr(sl.sourceConflict),
    requiredObjects: asArr(sl.requiredObjects),
    requiredAction: safeStr(sl.requiredAction),
    affectedGroups: asArr(sl.affectedGroups),

    satireThemaKonkret: safeStr(va.satireThemaKonkret),
    satireKonfliktKonkret: safeStr(va.satireKonfliktKonkret),
    visualPflichthandlung: safeStr(va.visualPflichthandlung),
    visualBetroffene: asArr(va.visualBetroffene),
    visualUeberzeichnung: safeStr(va.visualUeberzeichnung),

    kurzfassung: safeStr(row.kurzfassung),
    warumRelevant: safeStr(row.warumRelevant),

    sourceLockValid: row.sourceLockValid === true,
    visualAnchorsValid: row.visualAnchorsValid === true,
    guardValid: row.guardValid === true,
    visualGuardErrors: asArr(row.visualGuardErrors)
  }
};

